<body>
    <div id="score-display">得分: 0</div>
    <canvas id="gameCanvas"></canvas>

    <div id="game-over-screen">
        <h1>游戏结束！</h1>
        <p>你的得分是: <span id="final-score">0</span></p>
        <button id="restart-button">重新开始</button>
    </div>

    <script>
        const canvas = document.getElementById('gameCanvas');
        const ctx = canvas.getContext('2d');
        const scoreDisplay = document.getElementById('score-display');
        const gameOverScreen = document.getElementById('game-over-screen');
        const finalScoreDisplay = document.getElementById('final-score');
        const restartButton = document.getElementById('restart-button');

        // Canvas 尺寸
        canvas.width = 360;
        canvas.height = 640;

        // 游戏设置
        const gridSize = 20; // 每个方块的大小
        const tileCountX = canvas.width / gridSize;
        const tileCountY = canvas.height / gridSize;
        let snake = [];
        let food = {};
        let dx = 0; // x方向速度
        let dy = 0; // y方向速度
        let score = 0;
        let gameOver = false;
        let gameInterval;
        let gameSpeed = 150; // 游戏速度（毫秒），值越小越快
        let changingDirection = false; // 防止在同一帧内多次改变方向

        // 初始化游戏
        function initGame() {
            snake = [
                { x: 10, y: 10 },
                { x: 9, y: 10 },
                { x: 8, y: 10 }
            ];
            dx = 1;
            dy = 0;
            score = 0;
            gameOver = false;
            gameSpeed = 150; // 重置速度
            scoreDisplay.textContent = `得分: ${score}`;
            gameOverScreen.style.display = 'none';
            generateFood();
            if (gameInterval) clearInterval(gameInterval); // 清除旧的interval
            gameInterval = setInterval(gameLoop, gameSpeed); // 启动游戏循环
        }

        // 生成食物
        function generateFood() {
            let newFoodX, newFoodY;
            let collisionWithSnake;
            do {
                newFoodX = Math.floor(Math.random() * tileCountX);
                newFoodY = Math.floor(Math.random() * tileCountY);
                collisionWithSnake = false;
                for (let i = 0; i < snake.length; i++) {
                    if (snake[i].x === newFoodX && snake[i].y === newFoodY) {
                        collisionWithSnake = true;
                        break;
                    }
                }
            } while (collisionWithSnake);
            food = { x: newFoodX, y: newFoodY };
        }

        // 绘制函数
        function draw() {
            // 清空画布
            ctx.clearRect(0, 0, canvas.width, canvas.height);
            ctx.fillStyle = '#000';
            ctx.fillRect(0, 0, canvas.width, canvas.height);

            // 绘制食物
            ctx.fillStyle = '#f00'; // 红色
            ctx.strokeStyle = '#800';
            ctx.fillRect(food.x * gridSize, food.y * gridSize, gridSize, gridSize);
            ctx.strokeRect(food.x * gridSize, food.y * gridSize, gridSize, gridSize);

            // 绘制蛇
            for (let i = 0; i < snake.length; i++) {
                ctx.fillStyle = (i === 0) ? '#0f0' : '#0c0'; // 蛇头绿色，身体深绿色
                ctx.strokeStyle = '#080';
                ctx.fillRect(snake[i].x * gridSize, snake[i].y * gridSize, gridSize, gridSize);
                ctx.strokeRect(snake[i].x * gridSize, snake[i].y * gridSize, gridSize, gridSize);
            }
        }

        // 更新游戏状态
        function update() {
            if (gameOver) return;

            changingDirection = false; // 允许在下一帧改变方向

            const head = { x: snake[0].x + dx, y: snake[0].y + dy };

            // 检查碰撞
            // 撞墙
            if (head.x < 0 || head.x >= tileCountX || head.y < 0 || head.y >= tileCountY) {
                endGame();
                return;
            }
            // 撞到自己
            for (let i = 1; i < snake.length; i++) {
                if (head.x === snake[i].x && head.y === snake[i].y) {
                    endGame();
                    return;
                }
            }

            snake.unshift(head); // 将新头部添加到蛇的数组开头

            // 吃到食物
            if (head.x === food.x && head.y === food.y) {
                score += 10;
                scoreDisplay.textContent = `得分: ${score}`;
                generateFood();
                // 提高游戏速度
                if (gameSpeed > 50) { // 限制最小速度
                    gameSpeed -= 5; // 每次吃食物速度加快
                    clearInterval(gameInterval);
                    gameInterval = setInterval(gameLoop, gameSpeed);
                }
            } else {
                snake.pop(); // 移除蛇尾
            }
        }

        // 游戏循环
        function gameLoop() {
            update();
            draw();
        }

        // 结束游戏
        function endGame() {
            gameOver = true;
            clearInterval(gameInterval); // 停止游戏循环
            finalScoreDisplay.textContent = score;
            gameOverScreen.style.display = 'flex'; // 显示游戏结束界面
        }

        // 键盘事件监听
        document.addEventListener('keydown', changeDirection);

        function changeDirection(event) {
            if (changingDirection || gameOver) return;
            changingDirection = true;

            const keyPressed = event.key;
            const goingUp = dy === -1;
            const goingDown = dy === 1;
            const goingLeft = dx === -1;
            const goingRight = dx === 1;

            if ((keyPressed === 'ArrowLeft' || keyPressed === 'a') && !goingRight) {
                dx = -1;
                dy = 0;
            } else if ((keyPressed === 'ArrowUp' || keyPressed === 'w') && !goingDown) {
                dx = 0;
                dy = -1;
            } else if ((keyPressed === 'ArrowRight' || keyPressed === 'd') && !goingLeft) {
                dx = 1;
                dy = 0;
            } else if ((keyPressed === 'ArrowDown' || keyPressed === 's') && !goingUp) {
                dx = 0;
                dy = 1;
            }
        }

        // 触摸事件监听 (适用于移动设备)
        let touchStartX = 0;
        let touchStartY = 0;

        canvas.addEventListener('touchstart', e => {
            if (gameOver) return;
            touchStartX = e.touches[0].clientX;
            touchStartY = e.touches[0].clientY;
            e.preventDefault(); // 阻止默认的滚动行为
        });

        canvas.addEventListener('touchmove', e => {
            if (gameOver || changingDirection) return;
            e.preventDefault(); // 阻止默认的滚动行为
        });

        canvas.addEventListener('touchend', e => {
            if (gameOver || changingDirection) return;
            changingDirection = true;

            const touchEndX = e.changedTouches[0].clientX;
            const touchEndY = e.changedTouches[0].clientY;

            const deltaX = touchEndX - touchStartX;
            const deltaY = touchEndY - touchStartY;

            const goingUp = dy === -1;
            const goingDown = dy === 1;
            const goingLeft = dx === -1;
            const goingRight = dx === 1;

            if (Math.abs(deltaX) > Math.abs(deltaY)) { // 水平滑动
                if (deltaX > 0 && !goingLeft) { // 向右滑动
                    dx = 1;
                    dy = 0;
                } else if (deltaX < 0 && !goingRight) { // 向左滑动
                    dx = -1;
                    dy = 0;
                }
            } else { // 垂直滑动
                if (deltaY > 0 && !goingUp) { // 向下滑动
                    dx = 0;
                    dy = 1;
                } else if (deltaY < 0 && !goingDown) { // 向上滑动
                    dx = 0;
                    dy = -1;
                }
            }
        });


        // 重新开始按钮事件监听
        restartButton.addEventListener('click', initGame);

        // 首次加载页面时初始化游戏
        initGame();
    </script>
</body>
</html>
